final:
module fibonacci_lfsr(
  input clk,
  input rst_n,
  output reg [4:0] lfsr
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (~rst_n)
      lfsr <= 5'b00001;
    else
      lfsr <= {lfsr[3:0], lfsr[4] ^ lfsr[2]};
  end

endmodule
